<?php
namespace App\Services\Admin;
use App\Models\TravelRoute; use Illuminate\Support\Arr; use Illuminate\Support\Facades\DB;
class RouteService { public function save(array $data, ?TravelRoute $route=null): TravelRoute { return DB::transaction(function() use($data,$route){ $route ??= new TravelRoute(); $route->fill(Arr::only($data,['name','origin_location_id','destination_location_id','estimated_minutes','status']))->save(); $route->stops()->delete(); foreach($data['stops'] ?? [] as $i=>$stop) if(!empty($stop['location_id'])) $route->stops()->create(['location_id'=>$stop['location_id'],'stop_order'=>$stop['stop_order'] ?? $i+1,'arrival_offset_minutes'=>$stop['arrival_offset_minutes'] ?? 0,'departure_offset_minutes'=>$stop['departure_offset_minutes'] ?? 0]); $route->charges()->delete(); foreach($data['charges'] ?? [] as $charge) if(!empty($charge['name'])) $route->charges()->create(['name'=>$charge['name'],'amount'=>$charge['amount'] ?? 0,'type'=>$charge['type'] ?? 'fare']); return $route; }); } }
